class Trie:
    def __init__(self):
        self.root = TrieNode()
        self.max_bit_index = 30 # For non-negative integers up to 2^31 - 1

    def insert(self, num):
        node = self.root
        for i in range(self.max_bit_index, -1, -1):
            bit = (num >> i) & 1
            if not node.children[bit]:
                node.children[bit] = TrieNode()
            node = node.children[bit]

    def find_min_xor_pair(self, num):
        node = self.root
        current_min_xor_found = 0

        for i in range(self.max_bit_index, -1, -1):
            bit = (num >> i) & 1

            if node.children[bit]:
                node = node.children[bit]
            else:
                node = node.children[1 - bit]
                current_min_xor_found |= (1 << i)

        return current_min_xor_found

